function handlePDFAction() {
  if (!buildReportHTML()) return;
  showToast(t("toast_pdf_gen"), "info");

  const element = document.getElementById("print-container");
  const appWrapper = document.getElementById("app-wrapper");

  // 1. حفظ إعدادات الـ body الأصلية عشان نرجعها بعد الطباعة
  const origOverflow = document.body.style.overflow;
  const origHeight = document.body.style.height;

  // 2. إخفاء واجهة التطبيق
  appWrapper.style.display = "none";

  // 3. إصلاح "الصفحة البيضاء": فك قفل طول الصفحة عشان التقرير ياخد مساحته الطبيعية
  document.body.style.overflow = "visible";
  document.body.style.height = "auto";

  // 4. إظهار التقرير
  element.style.display = "block";

  // 5. 🚀 إصلاح "القص": إجبار التقرير على الالتصاق باليسار (حتى في اللغة العربية)
  // top: 0, right: auto, bottom: 0, left: 0
  element.style.setProperty("position", "static", "important");
  element.style.setProperty("margin", "0 auto 0 0", "important");

  // نطلع لأول الصفحة فوق عشان نضمن إن الصورة تبدأ من أول التقرير
  window.scrollTo(0, 0);

  // مهلة نص ثانية بس عشان المتصفح يرسم الجداول والصور
  setTimeout(() => {
    const pName = projectMeta.projectName
      ? projectMeta.projectName.replace(/\s+/g, "_")
      : "H2_Pinch";
    const opt = {
      margin: [10, 10, 10, 10],
      filename: pName + "_Report.pdf",
      image: { type: "jpeg", quality: 1 },
      pagebreak: { mode: ["css", "legacy"], before: ".print-page-break" },
      html2canvas: {
        scale: 2,
        useCORS: true,
        logging: false,
        // شيلنا إحداثيات الـ width والـ x عشان المكتبة تقرأ الحجم الطبيعي للتقرير براحتها
      },
      jsPDF: { unit: "mm", format: "a4", orientation: "portrait" },
    };

    html2pdf()
      .set(opt)
      .from(element)
      .save()
      .then(() => {
        // استرجاع كل شيء كما كان بعد نجاح التحميل
        element.style.display = "none";
        element.style.margin = "0 auto";
        appWrapper.style.display = "flex";

        // إرجاع قيود الـ body لحفظ تصميم التطبيق
        document.body.style.overflow = origOverflow;
        document.body.style.height = origHeight;

        showToast(t("toast_pdf_done"), "success");
      })
      .catch((err) => {
        console.error(err);
        // استرجاع كل شيء لو حصل خطأ
        element.style.display = "none";
        element.style.margin = "0 auto";
        appWrapper.style.display = "flex";

        document.body.style.overflow = origOverflow;
        document.body.style.height = origHeight;

        showToast(t("toast_pdf_err"), "error");
      });
  }, 500);
}
